import{_ as e,o as t,c as d,a2 as o}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Configuração de canais de upload","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/upload/index.md","filePath":"pt-BR/upload/index.md","lastUpdated":1781962217000}'),r={name:"pt-BR/upload/index.md"};function i(s,a,n,l,c,p){return t(),d("div",null,[...a[0]||(a[0]=[o('<h1 id="configuracao-de-canais-de-upload" tabindex="-1">Configuração de canais de upload <a class="header-anchor" href="#configuracao-de-canais-de-upload" aria-label="Permalink to &quot;Configuração de canais de upload&quot;">​</a></h1><p>No ImgBed, cada destino de armazenamento é configurado como um canal. Você decide onde salvar imagens, vídeos, áudios e outros arquivos pela configuração de upload.</p><h2 id="onde-configurar" tabindex="-1">Onde configurar <a class="header-anchor" href="#onde-configurar" aria-label="Permalink to &quot;Onde configurar&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configurações do sistema -&gt; Configurações de upload</span></span></code></pre></div><p>Ali você pode adicionar canais, habilitar ou desabilitar, definir limite de capacidade, adicionar observações e testar conexões.</p><h2 id="canais-disponiveis" tabindex="-1">Canais disponíveis <a class="header-anchor" href="#canais-disponiveis" aria-label="Permalink to &quot;Canais disponíveis&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Canal</th><th>Uso principal</th></tr></thead><tbody><tr><td>Cloudflare R2</td><td>Armazenamento de objetos na Cloudflare</td></tr><tr><td>S3</td><td>AWS S3, Backblaze B2, MinIO e serviços compatíveis</td></tr><tr><td>Google Drive</td><td>Salvar no Google Drive</td></tr><tr><td>OneDrive</td><td>Salvar no Microsoft OneDrive</td></tr><tr><td>Dropbox</td><td>Salvar no Dropbox</td></tr><tr><td>pCloud</td><td>Salvar no pCloud</td></tr><tr><td>WebDAV</td><td>NAS, discos em nuvem ou serviços compatíveis com WebDAV</td></tr><tr><td>Telegram</td><td>Usar um canal do Telegram como destino</td></tr><tr><td>Discord</td><td>Usar um canal do Discord como destino</td></tr><tr><td>GitHub Releases</td><td>Salvar em Release Assets do GitHub</td></tr><tr><td>GitLab Packages</td><td>Salvar no Generic Package Registry do GitLab</td></tr><tr><td>Hugging Face</td><td>Salvar em um repositório do Hugging Face</td></tr><tr><td>Yandex</td><td>Salvar no Yandex Disk</td></tr></tbody></table><h2 id="antes-de-adicionar" tabindex="-1">Antes de adicionar <a class="header-anchor" href="#antes-de-adicionar" aria-label="Permalink to &quot;Antes de adicionar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Ponto</th><th>O que conferir</th></tr></thead><tbody><tr><td>Conta de armazenamento</td><td>A conta onde os arquivos serão salvos</td></tr><tr><td>API Key / Token</td><td>Credenciais exigidas por cada canal</td></tr><tr><td>Diretório de armazenamento</td><td>Normalmente <code>imgbed</code>, salvo se você quiser outra pasta</td></tr><tr><td>Limite de capacidade</td><td>Se o canal deve parar de receber arquivos ao atingir certo uso</td></tr><tr><td>Domínio público</td><td>Se você vai usar CDN ou domínio personalizado</td></tr></tbody></table><h2 id="depois-de-salvar" tabindex="-1">Depois de salvar <a class="header-anchor" href="#depois-de-salvar" aria-label="Permalink to &quot;Depois de salvar&quot;">​</a></h2><ol><li>Confira se o cartão do canal aparece.</li><li>Verifique se o canal está habilitado.</li><li>Veja se credenciais e diretório foram salvos corretamente.</li><li>Execute consulta de capacidade se o canal oferecer isso.</li><li>Envie uma imagem de teste e abra o link retornado.</li></ol><p>Se falhar, revise primeiro credenciais, permissões, diretório de destino e limites da API do provedor.</p>',12)])])}const h=e(r,[["render",i]]);export{m as __pageData,h as default};
